// Example: verify HMAC and replay
const crypto = require('crypto');
function verify(payload, signature, secret, nonce, redis) {
  const h = crypto.createHmac('sha256', secret).update(payload).digest('hex');
  if (h !== signature) return false;
  // idempotency: ensure nonce not seen
  const seen = redis.setnx(`nonce:${nonce}`, '1');
  if (!seen) return false;
  redis.expire(`nonce:${nonce}`, 300);
  return true;
}
```

